import { useEffect, useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

export default function Dashboard() {
  const [productos, setProductos] = useState([]);
  const [nuevoProducto, setNuevoProducto] = useState({
    nombre: "",
    precio: "",
    stock: "",
  });
  const [editando, setEditando] = useState(null);

  // 🔹 Obtener productos
  const obtenerProductos = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/productos");
      setProductos(res.data);
    } catch (error) {
      console.error("Error al obtener productos:", error);
    }
  };

  useEffect(() => {
    obtenerProductos();
  }, []);

  // 🔹 Manejar cambios del formulario
  const handleChange = (e) => {
    setNuevoProducto({ ...nuevoProducto, [e.target.name]: e.target.value });
  };

  // 🔹 Crear o actualizar producto
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editando) {
        await axios.put(
          `http://localhost:5000/api/productos/${editando.productoID}`,
          nuevoProducto
        );
      } else {
        await axios.post("http://localhost:5000/api/productos", nuevoProducto);
      }

      setNuevoProducto({ nombre: "", precio: "", stock: "" });
      setEditando(null);
      obtenerProductos();
    } catch (error) {
      console.error("Error al guardar producto:", error);
    }
  };

  // 🔹 Editar producto
  const editarProducto = (producto) => {
    setNuevoProducto({
      nombre: producto.nombre,
      precio: producto.precio,
      stock: producto.stock,
    });
    setEditando(producto);
  };

  // 🔹 Eliminar producto
  const eliminarProducto = async (id) => {
    if (window.confirm("¿Seguro que deseas eliminar este producto?")) {
      try {
        await axios.delete(`http://localhost:5000/api/productos/${id}`);
        obtenerProductos();
      } catch (error) {
        console.error("Error al eliminar producto:", error);
      }
    }
  };

  return (
    <div className="container mt-5">
      <div className="card shadow-lg p-4">
        <h1 className="text-center mb-4">🛍️ Gestión de Productos</h1>

        {/* Formulario */}
        <form onSubmit={handleSubmit} className="mb-4">
          <div className="row g-3">
            <div className="col-md-4">
              <input
                type="text"
                name="nombre"
                value={nuevoProducto.nombre || ""}
                onChange={handleChange}
                placeholder="Nombre"
                className="form-control"
                required
              />
            </div>
            <div className="col-md-4">
              <input
                type="number"
                name="precio"
                value={nuevoProducto.precio || ""}
                onChange={handleChange}
                placeholder="Precio"
                className="form-control"
                required
              />
            </div>
            <div className="col-md-4">
              <input
                type="number"
                name="stock"
                value={nuevoProducto.stock || ""}
                onChange={handleChange}
                placeholder="Stock"
                className="form-control"
                required
              />
            </div>
          </div>

          <div className="text-center mt-3">
            <button className="btn btn-primary me-2" type="submit">
              {editando ? "Actualizar" : "Agregar"}
            </button>
            {editando && (
              <button
                type="button"
                onClick={() => {
                  setEditando(null);
                  setNuevoProducto({ nombre: "", precio: "", stock: "" });
                }}
                className="btn btn-secondary"
              >
                Cancelar
              </button>
            )}
          </div>
        </form>

        {/* Tabla */}
        <table className="table table-striped table-bordered align-middle">
          <thead className="table-dark">
            <tr>
              <th>ID</th>
              <th>Nombre</th>
              <th>Precio</th>
              <th>Stock</th>
              <th>Acciones</th>
            </tr>
          </thead>
          <tbody>
            {productos.length === 0 ? (
              <tr>
                <td colSpan="5" className="text-center">
                  No hay productos registrados.
                </td>
              </tr>
            ) : (
              productos.map((p) => (
                <tr key={p.productoID}>
                  <td>{p.productoID}</td>
                  <td>{p.nombre}</td>
                  <td>${p.precio}</td>
                  <td>{p.stock}</td>
                  <td>
                    <button
                      onClick={() => editarProducto(p)}
                      className="btn btn-warning btn-sm me-2"
                    >
                      Editar
                    </button>
                    <button
                      onClick={() => eliminarProducto(p.productoID)}
                      className="btn btn-danger btn-sm"
                    >
                      Eliminar
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
